class Variable:
    def __init__(self, value):
        self.value = value
        self.grad = None

    def backward(self):
        raise NotImplementedError

    def __add__(self, other):
        return Add(self, other)

    def __mul__(self, other):
        return Mul(self, other)

class Add(Variable):
    def __init__(self, left, right):
        super().__init__(left.value + right.value)
        self.left = left
        self.right = right

    def backward(self):
        self.left.grad = self.grad + self.right.grad
        self.right.grad = self.grad + self.left.grad
        return self.grad

class Mul(Variable):
    def __init__(self, left, right):
        super().__init__(left.value * right.value)
        self.left = left
        self.right = right

    def backward(self):
        self.left.grad = self.grad * self.right.value
        self.right.grad = self.grad * self.left.value
        return self.grad

