```objectivec
- (void)segmentControlChanged:(HMSegmentedControl *)sender {
    // Get the current child view controllers
    NSArray *childViewControllers = self.childViewControllers;

    // Get the old and new view controllers
    UIViewController *oldViewController = [childViewControllers firstObject];
    UIViewController *newViewController = childViewControllers[sender.selectedSegmentIndex];

    // Hide the old view controller
    oldViewController.view.hidden = YES;

    // Show the new view controller
    newViewController.view.hidden = NO;

    // Animate the transition
    [UIView animateWithDuration:0.5 animations:^{
        oldViewController.view.alpha = 0.0;
        newViewController.view.alpha = 1.0;
    } completion:^(BOOL finished) {
        // Reset the alpha values
        oldViewController.view.alpha = 1.0;
        newViewController.view.alpha = 1.0;
    }];
}
