public abstract class BaseRepository<T> : IRepository<T> where T : class
{
    protected readonly DbContext _context;
    protected readonly DbSet<T> _dbSet;

    protected BaseRepository(DbContext context)
    {
        _context = context;
        _dbSet = context.Set<T>();
    }

    public virtual async Task<T> FindAsync(Expression<Func<T, bool>> predicate)
    {
        return await _dbSet.FirstOrDefaultAsync(predicate);
    }

    public virtual async Task<List<T>> FindAllAsync(Expression<Func<T, bool>> predicate)
    {
        return await _dbSet.Where(predicate).ToListAsync();
    }

    public virtual async Task<T> FindByDynamicAsync(string propertyName, object value)
    {
        var parameter = Expression.Parameter(typeof(T));
        var member = Expression.Property(parameter, propertyName);
        var constant = Expression.Constant(value);
        var body = Expression.Equal(member, constant);
        var lambda = Expression.Lambda<Func<T, bool>>(body, parameter);
        return await _dbSet.FirstOrDefaultAsync(lambda);
    }

